examples.code:
resource "huaweicloud_modelartsv2_workflow" "test" {
  name         = "demo-workflow"
  description  = "workflow with steps"
  workspace_id = "0"

  steps {
    name = "training"
    type = "job"

    policy {
      poll_interval_seconds = 60
      max_execution_minutes = 120
    }
  }

  storages {
    name = "workflow_storage"
    type = "obs"
    path = "/obs-bucket/workflow/"
  }

  labels = ["terraform", "test"]
}
